actions.script:
import org.moqui.agent.AgentConfigUtil
import org.moqui.context.ExecutionContext
import org.moqui.impl.context.UserFacadeImpl.UserInfo

ExecutionContext ec = context.ec

// Permissions are handled by Moqui's artifact authorization system
// Users must be in appropriate MCP_* groups with access to the MCP artifact groups

ec.logger.info("MCP Initialize for session ${sessionId}, user ${ec.user.userId}")

// Validate protocol version - support common MCP versions with version negotiation
def supportedVersions = ["2025-11-25", "2025-06-18", "2024-11-05", "2024-10-07", "2023-06-05"]
if (!supportedVersions.contains(protocolVersion)) {
    throw new Exception("Unsupported protocol version: ${protocolVersion}. Supported versions: ${supportedVersions.join(', ')}")
}

// Get current user context (if authenticated)
def userId = ec.user.userId
def userAccountId = userId ? userId : null

// Try to load root instructions from wiki
def instructions = null
try {
    def wikiPage = ec.entity.find("moqui.resource.wiki.WikiPage")
        .condition("wikiSpaceId", "MCP_SCREEN_DOCS")
        .condition("pagePath", "root")
        .useCache(true)
        .one()

    if (wikiPage) {
        def wikiSpace = ec.entity.find("moqui.resource.wiki.WikiSpace")
            .condition("wikiSpaceId", wikiPage.wikiSpaceId)
            .one()

        if (wikiSpace) {
            def pageLocation = wikiSpace.rootPageLocation
            if (!pageLocation.endsWith('/')) pageLocation += '/'
            pageLocation += wikiPage.pagePath + '.md'

            def pageRef = ec.resource.getLocationReference(pageLocation)
            def wikiText = pageRef?.getText()
            if (wikiText) {
                instructions = wikiText
                ec.logger.info("MCP Initialize: Loaded root instructions from wiki")
            }
        }
    }
} catch (Exception e) {
    ec.logger.debug("Could not load root instructions from wiki: ${e.message}")
}

// Fallback to hardcoded instructions if wiki not available
if (!instructions) {
    instructions = "This server provides access to Moqui ERP through MCP. For create, update, assign, close, confirm, submit, delete, or other state-changing user requests, do not answer from general knowledge and do not only describe what you would do. You must call a Moqui tool. For natural-language user intents, especially multi-entity requests like project plus milestones plus tasks, use moqui_resolve_and_execute first. Use moqui_search_agent_prompts → moqui_get_agent_document → moqui_execute_agent_prompt only when you already know the exact document to run. If you execute a root create document directly for a composite request, include queryText so Moqui can decompose the aggregate. Use moqui_get_runtime_context and moqui_get_session_context to ground follow-up prompts. Do not bypass Moqui artifact authorization. Use moqui_check_artifact_access to verify access before mutating operations."
}

// Build server capabilities - don't fetch actual tools/resources during init
// Tools and resources will be discovered via separate list requests per MCP spec
def serverCapabilities = [
    tools: [listChanged: true],
    resources: [subscribe: true, listChanged: true],
    logging: [:]
]

// Build server info with useful metadata
def moquiVersion = ec.factory.moquiVersion ?: "Unknown"
def runtimePath = ec.factory.runtimePath ?: "Unknown"

Set userGroupIdSet = (ec.user.userGroupIdSet ?: []) as Set
boolean isPrivileged = userGroupIdSet.contains('ADMIN') || userGroupIdSet.contains('MCP_DEBUG')

def serverInfo = [
    name: "Moqui MCP Server",
    version: "2.0.2",
    moquiVersion: moquiVersion,
    currentUser: ec.user?.username,
    currentUserId: ec.user?.userId
]
if (isPrivileged) {
    serverInfo.hostname = System.getenv("HOSTNAME") ?: System.getProperty("hostname", "Unknown")
    serverInfo.javaVersion = System.getProperty("java.version") ?: "Unknown"
    serverInfo.javaVendor = System.getProperty("java.vendor") ?: "Unknown"
    serverInfo.runtimePath = runtimePath
    try {
        serverInfo.serverStartTime = java.lang.management.ManagementFactory.getRuntimeMXBean().getStartTime()
    } catch (Exception ignored) {}
}

Map runtimeConfig = AgentConfigUtil.validateRuntimeConfiguration(ec, [checkIndexes: false])

result = [
    protocolVersion: protocolVersion,
    capabilities: serverCapabilities,
    serverInfo: serverInfo,
    sessionId: sessionId,
    instructions: instructions,
    runtimeConfiguration: [
        status: runtimeConfig.status,
        warnings: runtimeConfig.warnings,
        details: runtimeConfig.details
    ]
]

ec.logger.info("MCP Initialize for user ${userId} (session ${sessionId}): capabilities negotiated")

// Get current user information
def currentUser = ec.user.username
def currentUserId = ec.user.userId

// Try to get visit information if sessionId is provided
def visitInfo = null
if (sessionId) {
    try {
        def visit = ec.entity.find("moqui.server.Visit")
            .condition("visitId", sessionId)
            .one()

        if (visit) {
            visitInfo = [
                visitId: visit.visitId,
                userId: visit.userId,
                fromDate: visit.fromDate,
                lastUpdatedStamp: visit.lastUpdatedStamp
            ]
        }
    } catch (Exception e) {
        ec.logger.warn("Error getting visit info for sessionId ${sessionId}: ${e.message}")
    }
}

result = [
    timestamp: ec.user.getNowTimestamp(),
    status: "healthy",
    version: "2.0.2",
    sessionId: sessionId,
    currentUser: currentUser,
    currentUserId: currentUserId,
    visitInfo: visitInfo,
    architecture: "Visit-based sessions"
]
def runtimeConfig = ec.service.sync().name('org.moqui.agent.AgentRuntimeServices.check#RuntimeConfiguration').parameters([
    checkIndexes: true
]).call()
result.runtimeConfiguration = [
    status: runtimeConfig.status,
    errors: runtimeConfig.errors,
    warnings: runtimeConfig.warnings,
    details: runtimeConfig.details
]
if (runtimeConfig.status == 'error') result.status = 'degraded'
else if (runtimeConfig.status == 'warn') result.status = 'healthy_with_warnings'
